# Define a function to change the current working directory
def change_directory(directory):
    print(f"Changing the current working directory to {directory}...")
    try:
        os.chdir(directory)
        print("Current working directory changed successfully.")
    except FileNotFoundError:
        print("Directory not found.")

# Define a function to list all directories in the current working directory
def list_directories():
    print("Listing all directories in the current working directory...")
    directories = [f for f in os.listdir() if os.path.isdir(f)]
    print("Directories:")
    for directory in directories:
        print(directory)

